parameters.jsCode:
// Extract workflow list and prepare sync data
const response = $input.first().json;
const workflows = response.data || [];

const syncData = {
  timestamp: new Date().toISOString(),
  timestamp_est: new Date().toLocaleString('en-US', {
    timeZone: 'America/New_York',
    dateStyle: 'medium',
    timeStyle: 'medium'
  }),
  workflow_count: workflows.length,
  workflows: workflows.map(w => ({
    id: w.id,
    name: w.name,
    active: w.active,
    updated_at: w.updatedAt
  }))
};

return [{ json: syncData }];

// Create a summary file for the repo
const data = $input.first().json;

const summary = [
  `# n8n Workflow Sync Status`,
  ``,
  `**Last synced:** ${data.timestamp_est} (EST)`,
  `**Total workflows:** ${data.workflow_count}`,
  ``,
  `| Name | Active | Last Updated |`,
  `|------|--------|-------------|`,
  ...data.workflows.map(w => 
    `| ${w.name} | ${w.active ? '✅' : '❌'} | ${new Date(w.updated_at).toLocaleDateString('en-US')} |`
  ),
  ``,
  `---`,
  `*Auto-generated by n8n Workflow 13 — GitHub Sync*`
].join('\n');

return [{
  json: {
    summary: summary,
    ...data
  }
}];

